section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/java-spring.json",
  "type": "object",
  "required": ["feature", "controller", "service", "request_dto", "response_dto"],
  "properties": {
    "feature": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+$"},
    "controller": {
      "type": "object",
      "required": ["class_name", "has_transactional", "calls_repository_directly"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+Controller$"},
        "has_transactional": {"type": "boolean", "const": false},
        "calls_repository_directly": {"type": "boolean", "const": false},
        "list_endpoint_uses_pageable": {"type": "boolean"}
      }
    },
    "service": {
      "type": "object",
      "required": ["class_name", "transactional_present", "returns_entity"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+Service$"},
        "transactional_present": {"type": "boolean", "const": true},
        "returns_entity": {"type": "boolean", "const": false}
      }
    },
    "request_dto": {
      "type": "object",
      "required": ["class_name", "is_record", "has_bean_validation"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+Request$"},
        "is_record": {"type": "boolean", "const": true},
        "has_bean_validation": {"type": "boolean", "const": true}
      }
    },
    "response_dto": {
      "type": "object",
      "required": ["class_name", "is_record"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+Response$"},
        "is_record": {"type": "boolean", "const": true}
      }
    },
    "async": {
      "type": "object",
      "properties": {
        "self_invocation": {"type": "boolean", "const": false},
        "executor_name": {"type": "string"},
        "executor_bean_defined": {"type": "boolean"}
      }
    }
  }
}

example.code:
{
  "feature": "Orders",
  "controller": {"class_name": "OrdersController", "has_transactional": false, "calls_repository_directly": false, "list_endpoint_uses_pageable": true},
  "service": {"class_name": "OrdersService", "transactional_present": true, "returns_entity": false},
  "request_dto": {"class_name": "CreateOrderRequest", "is_record": true, "has_bean_validation": true},
  "response_dto": {"class_name": "OrderResponse", "is_record": true},
  "async": {"self_invocation": false, "executor_name": "emailExecutor", "executor_bean_defined": true}
}

{
  "feature": "Orders",
  "controller": {"class_name": "OrderCtrl", "has_transactional": true, "calls_repository_directly": true, "list_endpoint_uses_pageable": false},
  "service": {"class_name": "OrdersService", "transactional_present": false, "returns_entity": true},
  "request_dto": {"class_name": "CreateOrderReq", "is_record": false, "has_bean_validation": false},
  "response_dto": {"class_name": "OrderResp", "is_record": false},
  "async": {"self_invocation": true, "executor_name": "", "executor_bean_defined": false}
}
